using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using QuickCode.Demo.Infrastructure.Integration.Helpers;
using QuickCode.Demo.Infrastructure.Integration.Nswag;
using QuickCode.Demo.Infrastructure.Integration.Nswag.Clients.IdentityModuleApi.Contracts;
using QuickCode.Demo.Portal.Helpers;
using QuickCode.Demo.Portal.Models;

namespace QuickCode.Demo.Portal.ViewComponents;

public class PortalBreadcrumbViewComponent : ViewComponent
{
    private readonly IPortalMenusClient _portalMenusClient;
    private readonly IHttpContextAccessor _httpContextAccessor;

    public PortalBreadcrumbViewComponent(
        IPortalMenusClient portalMenusClient,
        IHttpContextAccessor httpContextAccessor)
    {
        _portalMenusClient = portalMenusClient;
        _httpContextAccessor = httpContextAccessor;
        ApplyBearerToken();
    }

    public async Task<IViewComponentResult> InvokeAsync()
    {
        var httpContext = _httpContextAccessor.HttpContext;
        if (PortalNavigationHelper.IsDashboardPage(httpContext))
            return Content(string.Empty);

        var requestPath = httpContext?.Request.Path.Value;
        var pageTitleOverride = ViewContext.ViewData["Title"]?.ToString();

        IReadOnlyList<PortalMenuDto> menuItems = new List<PortalMenuDto>();
        if (httpContext?.User.Identity?.IsAuthenticated == true)
        {
            var cachedItems = httpContext.Session.Get<List<PortalMenuDto>>("MenuItems");
            if (cachedItems == null)
            {
                var loadedMenus = new List<PortalMenuDto>(await _portalMenusClient.PortalMenusListAsync());
                menuItems = loadedMenus;
                httpContext.Session.Set("MenuItems", loadedMenus);
            }
            else
            {
                menuItems = cachedItems;
            }
        }

        var items = PortalNavigationHelper.BuildBreadcrumb(requestPath, menuItems, pageTitleOverride);
        return View(items);
    }

    private void ApplyBearerToken()
    {
        var httpContext = _httpContextAccessor.HttpContext;
        if (httpContext?.User.Identity?.IsAuthenticated != true)
            return;

        var accessToken = PortalApiTokenStore.GetAccessToken(httpContext);
        if (!string.IsNullOrEmpty(accessToken))
            ((ClientBase)_portalMenusClient).SetBearerToken(accessToken);
    }
}
